using Microsoft.Extensions.Logging;

namespace MyMauiApp;

public static class MauiProgram
{
    public static MauiApp CreateMauiApp()
    {
        var builder = MauiApp.CreateBuilder();
        builder
            .UseMauiApp<App>()
            .ConfigureFonts(fonts =>
            {
                fonts.AddFont("OpenSans-Regular.ttf", "OpenSansRegular");
            });

        // --- HTTP + Data Service: Singleton ---
        // One HttpClient and one DataService instance for the entire app.
        // REST clients are expensive to create (socket exhaustion) and
        // stateless, so a single shared instance is ideal.
        builder.Services.AddSingleton<HttpClient>(sp =>
        {
            return new HttpClient { BaseAddress = new Uri("https://api.example.com/") };
        });
        builder.Services.AddSingleton<IDataService, DataService>();

        // --- ViewModels: Transient ---
        // A fresh ViewModel every time a page is created, so each page
        // instance gets its own clean state. Avoids stale data when
        // navigating back and forth.
        builder.Services.AddTransient<MainViewModel>();
        builder.Services.AddTransient<DetailViewModel>();

        // --- Pages: Transient ---
        // New page instance per navigation, matching the ViewModel
        // lifetime. This is the standard MAUI pattern — Shell and
        // NavigationPage resolve a new page each time you navigate.
        builder.Services.AddTransient<MainPage>();
        builder.Services.AddTransient<DetailPage>();

#if DEBUG
        builder.Logging.AddDebug();
#endif

        return builder.Build();
    }
}

